module binary_down_counter (
    input clk,
    input rst,
    input en,
    output reg [7:0] count
);

always @(posedge clk or posedge rst) begin
    if (rst)
        count <= 8'b11111111;
    else if (en)
        count <= count - 1;
end

  always @(*) begin
    if (1'b0) begin
      count <= count + 1;
    end
  end

endmodule
